     1→import { Elysia } from 'elysia';
     2→import { cors } from '@elysiajs/cors';
     3→import { db } from './db';
     4→import { AppError } from './shared/errors';
     5→
     6→// Import all modules
     7→import { elementalsModule } from './modules/elementals';
     8→import { usersModule } from './modules/users';
     9→import { diceModule } from './modules/dice';
    10→import { itemsModule } from './modules/items';
    11→import { diceRollsModule } from './modules/dice-rolls';
    12→import { eventsModule } from './modules/events';
    13→import { evolutionModule } from './modules/evolution';
    14→
    15→export const app = new Elysia()
    16→  .use(cors())
    17→  // Global error handler
    18→  .onError(({ code, error, set }) => {
    19→    console.error('Error:', error);
    20→
    21→    // Handle custom AppError
    22→    if (error instanceof AppError) {
    23→      set.status = error.statusCode;
    24→      return {
    25→        error: error.message,
    26→        code: error.code,
    27→      };
    28→    }
    29→
    30→    // Handle Elysia validation errors
    31→    if (code === 'VALIDATION') {
    32→      set.status = 400;
    33→      return {
    34→        error: 'Validation failed',
    35→        code: 'VALIDATION_ERROR',
    36→        details: error.message,
    37→      };
    38→    }
    39→
    40→    // Handle not found
    41→    if (code === 'NOT_FOUND') {
    42→      set.status = 404;
    43→      return {
    44→        error: 'Route not found',
    45→        code: 'NOT_FOUND',
    46→      };
    47→    }
    48→
    49→    // Default error
    50→    set.status = 500;
    51→    return {
    52→      error: 'Internal server error',
    53→      code: 'INTERNAL_ERROR',
    54→      message: process.env.NODE_ENV === 'development' ? error : undefined,
    55→    };
    56→  })
    57→  // Root endpoint
    58→  .get('/api', () => ({
    59→    name: '🎮 Elementary Dices API',
    60→    version: '1.0.0',
    61→    description: 'A dice rolling collectible game with elementals',
    62→  }))
    63→  // Health check endpoint
    64→  .get('/api/health', async () => {
    65→    try {
    66→      await db.raw('SELECT 1');
    67→      return {
    68→        status: 'ok',
    69→        database: 'connected',
    70→        timestamp: new Date().toISOString(),
    71→      };
    72→    } catch (error) {
    73→      return {
    74→        status: 'error',
    75→        database: 'disconnected',
    76→        error: String(error),
    77→      };
    78→    }
    79→  })
    80→  // Register all feature modules
    81→  .use(elementalsModule)
    82→  .use(usersModule)
    83→  .use(diceModule)
    84→  .use(itemsModule)
    85→  .use(diceRollsModule)
    86→  .use(eventsModule)
    87→  .use(evolutionModule)
    88→  .listen(3000);
    89→
    90→export type App = typeof app;
    91→
    92→// Test database connection on startup
    93→db.raw('SELECT 1')
    94→  .then(() => console.log('✅ Database connected'))
    95→  .catch((err) => console.error('❌ Database connection failed:', err.message));
    96→
    97→console.log(`🦊 Elysia is running at ${app.server?.hostname}:${app.server?.port}`);
    98→console.log('\n📦 Registered modules:');
    99→console.log('  - Elementals (CRUD)');
   100→console.log('  - Users (CRUD + profiles)');
   101→console.log('  - Dice (Types + Player inventory)');
   102→console.log('  - Items (CRUD + Player inventory)');
   103→console.log('  - Dice Rolls (Core game mechanics)');
   104→console.log('  - Events (Wild encounters, PvP, Merchant)');
   105→console.log('  - Evolution (Combining elementals)');
   106→console.log('\n🎮 Ready to play!\n');
   107→
   108→// Graceful shutdown
   109→process.on('SIGINT', async () => {
   110→  console.log('\n🛑 Shutting down gracefully...');
   111→  await db.destroy();
   112→  console.log('✅ Database connections closed');
   113→  process.exit(0);
   114→});
   115→
