     8→
     9→export const usersModule = new Elysia({ prefix: '/api/users' })
    10→  .decorate('userService', new UserService())
    11→  // Get all users
    12→  .get('/', async ({ userService }) => {
    13→    const users = await userService.findAll();
    14→    return { users };
