    20→      const user = await userService.getUserProfile(params.id);
    21→      return { user };
    22→    },
    23→    {
    24→      params: t.Object({
    25→        id: t.String(),
    26→      }),
    27→    }
    28→  )
    29→  // Get user by username
    30→  .get(
    31→    '/username/:username',
    32→    async ({ params, userService }) => {
    33→      const user = await userService.findByUsername(params.username);
    34→      return { user };
    35→    },
    36→    {
    37→      params: t.Object({
    38→        username: t.String(),
    39→      }),
    40→    }
    41→  )
    42→  // Create new user
