import { t } from 'elysia';

// Element type
export type ElementType = 'fire' | 'water' | 'earth' | 'air' | 'lightning';

// Base stats interface
export interface BaseStats {
  health: number;
  attack: number;
  defense: number;
  speed: number;
}

